/* ⭐ 完美修复：输入框容器精确避让虚线并预留空隙 ⭐ */
/* ========================================================================= */
html:not(.gal-beauty-off) .chat .chat-bottom .uni-textarea .chat-input-scope,
html:not(.gal-beauty-off) #chat-input-scope{
    position:relative!important;
    background:transparent!important;
    border:none!important;
    border-radius:0!important;
    box-shadow:none!important;
    padding:2px 0 2px 0!important;
    margin:0!important;
    transform:none!important;
}

/* 修复1：原生Flex已经避开了左边图标，红线只需贴合容器最左侧起步，设为 4px 留出微小缝隙 */
html:not(.gal-beauty-off) .chat .chat-bottom .uni-textarea .chat-input-scope::before{
    content:""!important;
    position:absolute!important;
    left:4px!important; 
    top:2px!important;
    bottom:2px!important;
    width:1px!important;
    background:repeating-linear-gradient(
        180deg,
        rgba(160,72,72,.5) 0px,
        rgba(160,72,72,.5) 3px,
        transparent 3px,
        transparent 5px
    )!important;
    z-index:1!important;
    pointer-events:none!important;
}

html:not(.gal-beauty-off) .chat .chat-bottom .uni-textarea .chat-input-scope::after{
    content:none!important;
}

/* 修复2：真实文本框距离起跑线推开 16px，完美越过红虚线并留下呼吸空间 */
