    border-bottom: 1px dashed rgba(139,111,63,0.3)!important;
    border-radius: 4px 4px 0 0 !important;
    color:var(--diary-ink)!important;
    -webkit-text-fill-color:var(--diary-ink)!important;
    font-family:'Kalam','Caveat','楷体','KaiTi','Noto Serif SC',cursive,serif!important;
    font-size:14px!important;
    font-weight:500!important;
    line-height:22px!important;
    letter-spacing:0.5px!important;
    padding-left:16px!important;  /* 从 78px 缩减到合理的 16px */
    box-sizing: border-box!important; /* 关键：锁定盒模型 */
    text-shadow:0 0 1px rgba(58,40,23,.2)!important;
    outline:none!important;
    position:relative!important;
    z-index:2!important;
}

/* 提示文字本体隐藏原生内容 */
html:not(.gal-beauty-off) .chat .chat-bottom .uni-textarea textarea::placeholder,
html:not(.gal-beauty-off) .chatMsgTextarea textarea::placeholder {
    color: transparent !important;
    -webkit-text-fill-color: transparent !important;
}

html:not(.gal-beauty-off) .uni-textarea-placeholder {
    color: transparent !important;
    -webkit-text-fill-color: transparent !important;
    font-size: 0 !important;
    box-sizing: border-box !important; 
}

/* 修复3：独立占位符同步推开 16px，与文本框严丝合缝 */
