    content: "继续故事吧..." !important;
    color: var(--diary-ink-fade) !important;
    -webkit-text-fill-color: var(--diary-ink-fade) !important;
    font-size: 14px !important;
    font-family: 'Kalam', 'Caveat', '楷体', 'KaiTi', 'Noto Serif SC', cursive, serif !important;
    font-style: italic !important;
    line-height: 22px !important;
