    transform:translateY(-2px) scale(2.2)!important; 
    filter:drop-shadow(0 2px 6px rgba(232,185,106,.8)) drop-shadow(0 0 8px rgba(232,185,106,.4))!important;
}

html:not(.gal-beauty-off) .send-msg .btn-icon:active::before,
html:not(.gal-beauty-off) .chat-bottom-wapper .btn-icon:active::before{
    animation:quill-pulse .6s ease-out!important; 
}

@keyframes quill-pulse {
    0%   { transform:scale(2.0); filter:drop-shadow(0 0 4px rgba(232,185,106,.5)); }
    50%  { transform:scale(2.5); filter:drop-shadow(0 0 15px rgba(232,185,106,1)) drop-shadow(0 0 25px rgba(232,185,106,.8)) brightness(1.2); }
    100% { transform:scale(2.0); filter:drop-shadow(0 0 4px rgba(232,185,106,.5)); }
}

html:not(.gal-beauty-off) .send-msg .btn-icon::after,
html:not(.gal-beauty-off) .chat-bottom-wapper .btn-icon::after{
    content:""!important;
    position:absolute!important;
    width:100%!important;
    height:100%!important;
    border-radius:50%!important;
    background:radial-gradient(circle, rgba(232,185,106,.7) 0%, rgba(232,185,106,.2) 40%, transparent 70%)!important;
    z-index:1!important;
    opacity:0!important;
    pointer-events:none!important;
}

html:not(.gal-beauty-off) .send-msg .btn-icon:active::after,
html:not(.gal-beauty-off) .chat-bottom-wapper .btn-icon:active::after{
    animation:ink-glow .6s ease-out!important;
}

@keyframes ink-glow {
    0%   { opacity:0; transform:scale(0.8); }
    50%  { opacity:1; transform:scale(1.8); }
    100% { opacity:0; transform:scale(1); }
}

