/* 悬浮切换按钮 */
.gal-toggle-v7{
    position:fixed;
    right:0;
    bottom:15%;
    z-index:99999;
    width:38px;
    height:38px;
    background:rgba(20,38,58,.92);
    border:1px solid rgba(232,185,106,.45);
    border-right:none;
    border-radius:8px 0 0 8px;
    cursor:pointer;
    display:flex;
    align-items:center;
    justify-content:center;
    font-size:16px;
    color:#e8b96a;
    box-shadow:-2px 0 15px rgba(0,0,0,.4);
    backdrop-filter:blur(8px);
    transition:all .3s;
    user-select:none;
    text-shadow:0 0 8px rgba(232,185,106,.5);
}
.gal-toggle-v7:active{transform:scale(0.93);}
html.gal-beauty-off .gal-toggle-v7{
    opacity:.45;
    border-color:rgba(150,150,150,.3);
    color:#888;
    text-shadow:none;
    background:rgba(40,40,40,.7);
}
</style>

<div class="gal-v7-container">
    <div class="gal-toggle-v7" onclick="event.stopPropagation();var h=document.documentElement;if(h.classList.contains('gal-beauty-off')){h.classList.remove('gal-beauty-off');this.innerHTML='◈';}else{h.classList.add('gal-beauty-off');this.innerHTML='✧';}">◈</div>
    <img src="x" style="display:none" onerror="var d=document;var t=null;var ob=new MutationObserver(function(){if(d.documentElement.classList.contains('gal-beauty-off'))return;if(t)clearTimeout(t);t=setTimeout(function(){window.requestAnimationFrame(function(){try{if(d.documentElement.classList.contains('gal-beauty-off'))return;var cb=d.querySelector('.chat-body')||d;var ps=cb.querySelectorAll('.content p:not(.gal-q-processed)');for(var i=0;i<ps.length;i++){var p=ps[i];if(p.querySelector('.shell')||p.querySelector('[id^=\'WP_\']')){p.classList.add('gal-q-processed');continue;}var h=p.innerHTML;if(/("[^"]*")/.test(h))p.innerHTML=h.replace(/("[^"]*")/g,'<span class=\'gal-quote\'>$1</span>');p.classList.add('gal-q-processed');}}catch(e){}})},120)});ob.observe(d.body,{childList:true,subtree:true,characterData:true});this.remove();">
</div>
